        const entries: [ESObject, ESObject][] = Array.from(super.entries());
        let Accumulator: ESObject;
        let StartIndex: number = 0;

        if (Initial !== undefined) {
            Accumulator = Initial;
        } else {
            if (entries.length === 0) return undefined;
            Accumulator = entries[0][1];
            StartIndex = 1;
        }

        for (let i: number = StartIndex; i < entries.length; i++) {
            const entry: [ESObject, ESObject] = entries[i];
            Accumulator = (Fn as ESObject)(Accumulator, entry[1], entry[0], this);
        }

        return Accumulator;
    }

    map(Fn: ESObject): ESObject[] {
        if (typeof Fn !== "function") return [];
        const Arr: ESObject[] = new Array<ESObject>(this.size);
        const entries: [ESObject, ESObject][] = Array.from(super.entries());

        for (let i: number = 0; i < entries.length; i++) {
            const entry: [ESObject, ESObject] = entries[i];
            Arr[i] = (Fn as ESObject)(entry[1], entry[0], i, this);
        }
