    exists(Fn: ESObject): boolean {
        if (typeof Fn !== "function") return false;
        const entries: [ESObject, ESObject][] = Array.from(super.entries());
        for (let i: number = 0; i < entries.length; i++) {
            const entry: [ESObject, ESObject] = entries[i];
            if ((Fn as ESObject)(entry[1], entry[0], this)) return true;
        }
        return false;
    }

    some(Fn: ESObject): boolean {
        return this.exists(Fn);
    }

    every(Fn: ESObject): boolean {
        if (typeof Fn !== "function") return false;
        const entries: [ESObject, ESObject][] = Array.from(super.entries());
        for (let i: number = 0; i < entries.length; i++) {
            const entry: [ESObject, ESObject] = entries[i];
            if (!(Fn as ESObject)(entry[1], entry[0], this)) return false;
        }
        return true;
    }

    // ---------------------------------------------------------------- Collection management

    clone(): Collection {
        return new Collection(this.toPairObject());
    }

    merge(...Collections: Collection[]): Collection {
        const Clone: Collection = this.clone();
        for (let i: number = 0; i < Collections.length; i++) {
            const Col: Collection = Collections[i];
            const iter: IterableIterator<[ESObject, ESObject]> = Col.entries();
            let res: IteratorResult<[ESObject, ESObject]> = iter.next();
            while(!res.done) {
                Clone.set(res.value[0], res.value[1]);
                res = iter.next();
            }
        }
        return Clone;
    }

    implement(...Collections: Collection[]): Collection {
        for (let i: number = 0; i < Collections.length; i++) {
            const Col: Collection = Collections[i];
            const iter: IterableIterator<[ESObject, ESObject]> = Col.entries();
            let res: IteratorResult<[ESObject, ESObject]> = iter.next();
            while(!res.done) {
                this.set(res.value[0], res.value[1]);
                res = iter.next();
            }
        }
        return this;
    }

    intersect(Secondary: Collection): Collection {
        return this.filter((_: ESObject, Key: ESObject) => Secondary.has(Key));
    }

    difference(Secondary: Collection): Collection {
        const diff1: Collection = this.filter((_: ESObject, Key: ESObject) => !Secondary.has(Key));
        const diff2: Collection = Secondary.filter((_: ESObject, Key: ESObject) => !this.has(Key));
        return diff1.implement(diff2);
    }

    tap(Fn: ESObject): Collection {
        if (typeof Fn === "function") (Fn as ESObject)(this, this.size);
        return this;
    }

    each(Fn: ESObject): Collection {
        if (typeof Fn === "function") {
            const entries: [ESObject, ESObject][] = Array.from(super.entries());
            for (let i: number = 0; i < entries.length; i++) {
                const entry: [ESObject, ESObject] = entries[i];
                (Fn as ESObject)(entry[1], entry[0], this);
            }
        }
        return this;
    }

    sort(Fn: ESObject): Collection {
        if (typeof Fn !== "function") return this;

        // 显式声明回调参数为 Tuple
        const entries: [ESObject, ESObject][] = Array.from(super.entries());
        super.clear();

        entries.sort((a: [ESObject, ESObject], b: [ESObject, ESObject]) => {
            return Number((Fn as ESObject)(a[1], b[1], [a[0], a[1]]));
        });

        for (let i: number = 0; i < entries.length; i++) {
            this.set(entries[i][0], entries[i][1]);
        }
        return this;
    }
}

